// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ promote-candidate — guarded canonical promotion helper                   ║
// ╚══════════════════════════════════════════════════════════════════════════╝
'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

const fs = require('node:fs');
const path = require('node:path');
const {
  BENCHMARK_AGGREGATE_GATE,
  PROMOTION_GATES,
